noncompliant:
// Noncompliant: Function with variable arguments
void MyPrintf(const char* pFormat, ...) {
  va_list args;
  va_start(args, pFormat);
  // ... processing variable arguments
  va_end(args);
}

compliant:
// Compliant: Function with fixed parameters
void MyPrintfInt(const char* pFormat, int value) {
  printf(pFormat, value);
}

void MyPrintfString(const char* pFormat, const char* str) {
  printf(pFormat, str);
}
